"use client";

import { cn } from "@/lib/utils";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { IconAdjustments } from "@tabler/icons-react";
import { QUALITY_LEVELS } from "@/registry/new-york/quality/quality";
import type { QualityLevel } from "@/registry/new-york/quality/quality";
import type { PlaybackSpeed } from "@/registry/new-york/quality/types";
import { PLAYBACK_SPEEDS } from "@/registry/new-york/quality/types";

interface YtcnQualityProps {
  /** The quality level the user has selected (or "auto") */
  selectedQuality: QualityLevel | "auto";
  /** The quality level YouTube is actually playing at */
  actualQuality: QualityLevel | "";
  /** Quality levels available for this video */
  availableQualities: QualityLevel[];
  /** Called when the user picks a quality level */
  onQualityChange: (quality: QualityLevel | "auto") => void;
  /** Current playback speed — displayed in the same settings dropdown */
  playbackRate?: number;
  /** Called when the user picks a speed */
  onSpeedChange?: (rate: PlaybackSpeed) => void;
  /**
   * Portal container for fullscreen visibility.
   *
   * By default Radix portals dropdown content to document.body. When the
   * player is in fullscreen mode, the browser only renders elements INSIDE
   * the fullscreen element — anything portaled to body becomes invisible.
   * Passing containerRef.current makes the portal append inside the
   * fullscreen element, keeping the dropdown always visible.
   */
  containerRef?: React.RefObject<HTMLDivElement | null>;
}

/**
 * YtcnQuality — Quality selector dropdown with optional speed picker.
 *
 * Combines quality and speed selection into a single settings dropdown,
 * portaled into the player container for fullscreen compatibility.
 */
export function YtcnQuality({
  selectedQuality,
  actualQuality,
  availableQualities,
  onQualityChange,
  playbackRate,
  onSpeedChange,
  containerRef,
}: YtcnQualityProps) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <button
          onClick={(e) => e.stopPropagation()}
          className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
          aria-label="Settings"
        >
          <IconAdjustments className="size-5" />
        </button>
      </DropdownMenuTrigger>

      <DropdownMenuContent
        align="end"
        className="w-48"
        container={containerRef?.current ?? undefined}
        onClick={(e) => e.stopPropagation()}
      >
        {/* ── Quality ── */}
        <DropdownMenuLabel>Quality</DropdownMenuLabel>

        <DropdownMenuItem
          onClick={() => onQualityChange("auto")}
          className={cn(
            "cursor-pointer",
            selectedQuality === "auto" && "bg-accent"
          )}
        >
          <span className="flex-1">Auto</span>
          {selectedQuality === "auto" && actualQuality && (
            <span className="text-xs text-muted-foreground ml-1">
              ({QUALITY_LEVELS[actualQuality as QualityLevel]?.label})
            </span>
          )}
          {selectedQuality === "auto" && (
            <span className="text-primary ml-1">✓</span>
          )}
        </DropdownMenuItem>

        {availableQualities.length === 0 ? (
          <DropdownMenuItem disabled>
            <span className="text-muted-foreground text-xs italic">
              Play video to load qualities
            </span>
          </DropdownMenuItem>
        ) : (
          availableQualities.map((quality) => (
            <DropdownMenuItem
              key={quality}
              onClick={() => onQualityChange(quality)}
              className={cn(
                "cursor-pointer",
                selectedQuality === quality && "bg-accent"
              )}
            >
              <span className="flex-1">
                {QUALITY_LEVELS[quality].label}
              </span>
              {selectedQuality === quality && (
                <span className="text-primary">✓</span>
              )}
            </DropdownMenuItem>
          ))
        )}

        {/* ── Speed (optional) ── */}
        {onSpeedChange && (
          <>
            <DropdownMenuSeparator />
            <DropdownMenuLabel>Playback Speed</DropdownMenuLabel>
            {PLAYBACK_SPEEDS.map((speed) => (
              <DropdownMenuItem
                key={speed}
                onClick={() => onSpeedChange(speed)}
                className={cn(
                  "cursor-pointer",
                  playbackRate === speed && "bg-accent"
                )}
              >
                <span className="flex-1">
                  {speed === 1 ? "Normal" : `${speed}x`}
                </span>
                {playbackRate === speed && (
                  <span className="text-primary">✓</span>
                )}
              </DropdownMenuItem>
            ))}
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import type { QualityLevel } from "@/lib/ytcn/quality";

/* ================================================================ */
/*  Playback Speed                                                   */
/* ================================================================ */

export type PlaybackSpeed = 0.25 | 0.5 | 0.75 | 1 | 1.25 | 1.5 | 1.75 | 2;

export const PLAYBACK_SPEEDS: PlaybackSpeed[] = [
  0.25, 0.5, 0.75, 1, 1.25, 1.5, 1.75, 2,
];

/* ================================================================ */
/*  Player State                                                     */
/* ================================================================ */

export interface PlayerState {
  isPlaying: boolean;
  isMuted: boolean;
  volume: number; // 0–100
  currentTime: number; // seconds
  duration: number; // seconds
  loadedFraction: number; // 0–1 buffer progress
  isLoading: boolean;
  isFullscreen: boolean;
  playbackRate: PlaybackSpeed;
  selectedQuality: QualityLevel | "auto";
  actualQuality: QualityLevel | "";
  availableQualities: QualityLevel[];
}

/* ================================================================ */
/*  Player Options                                                   */
/* ================================================================ */

export interface YtcnPlayerOptions {
  /** YouTube video ID (the 11-character string, not a full URL) */
  videoId: string;
  /** Start playback automatically. Browsers require muted audio for this. */
  autoplay?: boolean;
  /** Initial quality hint — applied via both vq and setPlaybackQualityRange */
  defaultQuality?: QualityLevel | "auto";
  /** Initial playback rate */
  defaultSpeed?: PlaybackSpeed;
  /** Resume from this timestamp (seconds) */
  startAt?: number;
  /** Fired when the video reaches its end */
  onEnd?: () => void;
  /** Polled every 250ms during playback */
  onTimeUpdate?: (currentTime: number, duration: number) => void;
  /** Fired when the actual quality level changes */
  onQualityChange?: (quality: string) => void;
  /** Fired when the playback rate changes */
  onPlaybackRateChange?: (rate: number) => void;
}

/* ================================================================ */
/*  Controls Interface                                               */
/* ================================================================ */

export interface PlayerControls {
  play: () => void;
  pause: () => void;
  togglePlay: () => void;
  seekTo: (seconds: number) => void;
  seekRelative: (delta: number) => void;
  setVolume: (vol: number) => void;
  toggleMute: () => void;
  setSpeed: (rate: PlaybackSpeed) => void;
  setQuality: (quality: QualityLevel | "auto") => void;
  toggleFullscreen: () => void;
}

/* ================================================================ */
/*  Keyboard Shortcut Bindings                                       */
/* ================================================================ */

export interface KeyboardBindings {
  play?: string;
  mute?: string;
  fullscreen?: string;
  seekBack?: string;
  seekForward?: string;
}

export const DEFAULT_KEYBOARD_BINDINGS: Required<KeyboardBindings> = {
  play: " ",
  mute: "m",
  fullscreen: "f",
  seekBack: "ArrowLeft",
  seekForward: "ArrowRight",
};

/**
 * QUALITY_LEVELS — YouTube quality level identifiers mapped to human labels.
 *
 * The `order` field defines sort priority: 0 = highest quality, 7 = lowest.
 * These string keys are the exact values YouTube's IFrame API returns from
 * `getAvailableQualityLevels()` and accepts in `setPlaybackQuality()`.
 */
export const QUALITY_LEVELS = {
  highres: { label: "4K+", order: 0 },
  hd2160: { label: "4K", order: 1 },
  hd1440: { label: "1440p", order: 2 },
  hd1080: { label: "1080p", order: 3 },
  hd720: { label: "720p", order: 4 },
  large: { label: "480p", order: 5 },
  medium: { label: "360p", order: 6 },
  small: { label: "240p", order: 7 },
} as const;

export type QualityLevel = keyof typeof QUALITY_LEVELS;

/**
 * enforceQuality — Dual-strategy quality enforcement.
 *
 * Strategy B (JS API lock): Called after onReady AND on every PLAYING state
 * change. Sets both min and max quality to the same level, forcing YouTube
 * to stay within that exact range. This is what makes lower qualities like
 * 360p/240p actually stick — the vq playerVar (Strategy A, applied at player
 * creation time) alone is not enough for low qualities because YouTube may
 * silently upgrade them if it detects a fast connection.
 *
 * To release the lock and return to adaptive streaming, we set the range
 * from "small" to "highres" which allows YouTube full freedom.
 *
 * Strategy A (vq playerVar) is applied separately at player creation time
 * in the loader — see use-ytcn-player.ts for that path.
 */
export function enforceQuality(
  player: YT.Player | null,
  quality: QualityLevel | "auto"
): void {
  if (!player) return;
  try {
    if (quality === "auto") {
      // Release the quality lock — let YouTube choose freely
      if (typeof (player as any).setPlaybackQualityRange === "function") {
        (player as any).setPlaybackQualityRange("small", "highres");
      }
    } else {
      // Lock both min and max to the same level
      if (typeof (player as any).setPlaybackQualityRange === "function") {
        (player as any).setPlaybackQualityRange(quality, quality);
      }
      // Fallback: also call the single-quality setter if available
      if (typeof (player as any).setPlaybackQuality === "function") {
        (player as any).setPlaybackQuality(quality);
      }
    }
  } catch {
    /* YouTube API calls can throw if the player is in a bad state */
  }
}

/**
 * Filters and sorts raw quality strings from getAvailableQualityLevels()
 * into typed, ordered QualityLevel values.
 */
export function parseAvailableQualities(levels: string[]): QualityLevel[] {
  return levels
    .filter((q): q is QualityLevel => q in QUALITY_LEVELS)
    .sort((a, b) => QUALITY_LEVELS[a].order - QUALITY_LEVELS[b].order);
}
